SELECT DISTINCT FROM biz_activity a INNER JOIN biz_activity_scope s ON a.id = s.activity_id WHERE a.deleted = 0 AND a.status = 'PUBLISHED'
AND a.title LIKE CONCAT('%', #{query.keyword}, '%')
AND ( s.scope_type = 'ALL' OR s.scope_ref_id = #{userOrgId} OR #{ancestorPath} LIKE CONCAT('%/', s.scope_ref_id, '/%') ) ORDER BY a.publish_time DESC, a.id DESC LIMIT #{size} OFFSET #{offset}
